Console.WriteLine($"=== {agentType.FullName} ===");
foreach (var c in agentType.GetConstructors(BindingFlags.Public | BindingFlags.Instance))
    Console.WriteLine($"  ctor({string.Join(", ", c.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"))})");
foreach (var m in agentType.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly))
    Console.WriteLine($"  {m.ReturnType.Name} {m.Name}({string.Join(", ", m.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"))})");
foreach (var p in agentType.GetProperties(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly))
    Console.WriteLine($"  prop {p.PropertyType.Name} {p.Name}");

// Show ChatClientAgentOptions
var optType = asm.GetType("Microsoft.Agents.AI.ChatClientAgentOptions");
if (optType != null) {
    Console.WriteLine($"\n=== {optType.FullName} ===");
    foreach (var p in optType.GetProperties(BindingFlags.Public | BindingFlags.Instance))
        Console.WriteLine($"  prop {p.PropertyType.Name} {p.Name}");
}

// Show ChatClientAgentRunOptions
var runOptType = asm.GetType("Microsoft.Agents.AI.ChatClientAgentRunOptions");
if (runOptType != null) {
    Console.WriteLine($"\n=== {runOptType.FullName} ===");
    foreach (var p in runOptType.GetProperties(BindingFlags.Public | BindingFlags.Instance))
        Console.WriteLine($"  prop {p.PropertyType.Name} {p.Name}");
}

// Show base class hierarchy
Console.WriteLine($"\n=== Hierarchy ===");
var t = agentType;
while (t != null) {
    Console.WriteLine($"  {t.FullName}");
    t = t.BaseType;
}

// Check for InvokeAsync / InvokeStreamingAsync on base types
t = agentType;
while (t != null) {
    foreach (var m in t.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly)
        .Where(m => m.Name.Contains("Invoke") || m.Name.Contains("Run")))
        Console.WriteLine($"  [{t.Name}] {m.ReturnType.Name} {m.Name}({string.Join(", ", m.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"))})");
    t = t.BaseType;
}
CSEOF

