using System.ComponentModel;
using System.Text;
using Microsoft.Extensions.AI;
using Microsoft.Agents.AI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to run the research agent.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL")
    ?? "gpt-4o-mini-2024-07-18";

// --- Build the chat client via MEAI abstraction ---
IChatClient chatClient = new OpenAI.Chat.ChatClient(modelId, apiKey)
    .AsIChatClient();

// --- Register tools ---
var notebook = new Notebook();
var tools = new List<AITool>
{
    AIFunctionFactory.Create(WebSearchTool.Search),
    AIFunctionFactory.Create(notebook.SaveNote),
    AIFunctionFactory.Create(notebook.GetAllNotes),
};

// --- Create the research agent ---
var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research agent. When given a topic, follow these steps:
        1. Search the web with at least 3 different queries to gather diverse information.
        2. Save the most important findings as notes using the save_note tool.
        3. After gathering enough information, retrieve all your notes and produce
           a comprehensive, well-structured summary with source citations.

        Be thorough and always save notes before summarizing.
        """,
    name: "ResearchAgent",
    description: "Researches topics by searching the web and summarizing findings.",
    tools: tools);

// --- Prompt the user ---
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrWhiteSpace(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\n🔬 Researching: {topic}\n");

// --- Run the agent with streaming output ---
var session = await agent.CreateSessionAsync(
    conversationId: Guid.NewGuid().ToString());

await foreach (var update in agent.RunStreamingAsync(
    $"Research the following topic and provide a comprehensive summary: {topic}",
    session))
{
    if (!string.IsNullOrEmpty(update.Text))
        Console.Write(update.Text);
}

Console.WriteLine();

// ---------------------------------------------------------------------------
// Tool: Web Search
// ---------------------------------------------------------------------------

/// <summary>
/// Simulated web search tool.
/// Replace the body of <see cref="Search"/> with a real search API
/// (e.g. Bing Web Search, Google Custom Search) for production use.
/// </summary>
static class WebSearchTool
{
    [Description("Search the web for information on a given query. "
        + "Returns a list of results with titles, snippets, and URLs.")]
    public static string Search(
        [Description("The search query to look up")] string query)
    {
        Console.WriteLine($"  🔍 Searching: \"{query}\"");

        // Simulated results — swap with a real HTTP call in production.
        return $$"""
            Search results for "{{query}}":

            1. [Wikipedia] {{query}} — Overview
               {{query}} is a widely studied subject with applications across
               multiple domains. Key aspects include historical development,
               current research, and future directions.
               URL: https://en.wikipedia.org/wiki/{{Uri.EscapeDataString(query)}}

            2. [Research Journal] Recent Advances in {{query}}
               A 2025 survey covering the latest developments, methodologies,
               and breakthroughs. Researchers have identified several promising
               approaches and open challenges.
               URL: https://arxiv.org/search/?query={{Uri.EscapeDataString(query)}}

            3. [News] {{query}} — Latest Developments
               Industry experts weigh in on how {{query}} is shaping the future.
               Multiple organizations are investing heavily in this area.
               URL: https://news.example.com/{{Uri.EscapeDataString(query)}}
            """;
    }
}

// ---------------------------------------------------------------------------
// Tool: Notebook
// ---------------------------------------------------------------------------

/// <summary>
/// Note-taking tool that lets the agent save and retrieve research notes
/// across multiple search iterations.
/// </summary>
sealed class Notebook
{
    private readonly List<(DateTime Timestamp, string Content)> _notes = [];

    [Description("Save a research note for later reference when writing the summary.")]
    public string SaveNote(
        [Description("The note content to save")] string note)
    {
        _notes.Add((DateTime.UtcNow, note));
        Console.WriteLine($"  📝 Note #{_notes.Count} saved");
        return $"Note #{_notes.Count} saved successfully.";
    }

    [Description("Retrieve all saved research notes to use when writing a summary.")]
    public string GetAllNotes()
    {
        if (_notes.Count == 0)
            return "No notes have been saved yet.";

        var sb = new StringBuilder();
        sb.AppendLine($"Retrieved {_notes.Count} note(s):");
        for (var i = 0; i < _notes.Count; i++)
            sb.AppendLine($"\nNote #{i + 1} ({_notes[i].Timestamp:u}):\n{_notes[i].Content}");

        return sb.ToString();
    }
}

